  ('disabled-57f41407-moex-00216', 'disabled-57f41407', 'disabled-57f41407-moex-113-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '提起第二審上訴，如逾上訴期間，原第一審法院應如何處理？', '["以裁定駁回上訴", "以判決駁回上訴", "以裁定命補正", "以裁定移送第二審管轄法院"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:35+00:00", "source_pdf_sha1": "391f7c61502f", "answer_pdf_sha1": "032ff59ad495", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "505", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00217', 'disabled-57f41407', 'disabled-57f41407-moex-113-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於第二審訴訟程序，下列何者正確？', '["當事人在第二審訴訟程序提出新攻擊或防禦方法，應經法院許可", "第二審法院不得就假執行之上訴部分先為裁判", "當事人委任律師為訴訟代理人提起上訴後死亡，法院應裁定停止訴訟程序", "於第二審訴訟程序中，兩造得合意將事件移付調解"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:35+00:00", "source_pdf_sha1": "391f7c61502f", "answer_pdf_sha1": "032ff59ad495", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "505", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00218', 'disabled-57f41407', 'disabled-57f41407-moex-113-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '甲起訴請求乙返還借款新臺幣（下同）100 萬元，法院查明甲係借款 100 萬元予丙，甲、乙間並無消費借貸關係，下列何者正確？', '["法院應以當事人不適格為由，判決駁回甲之訴", "法院應判決命丙給付甲100萬元", "法院應以甲、乙間無消費借貸關係為由，判決駁回甲之訴", "法院應以乙欠缺當事人能力為由，裁定駁回甲之訴"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:35+00:00", "source_pdf_sha1": "391f7c61502f", "answer_pdf_sha1": "032ff59ad495", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "505", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00219', 'disabled-57f41407', 'disabled-57f41407-moex-113-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '對於第一審法院所為下列裁定，何者不得提起抗告？', '["更正判決之裁定", "駁回原告追加之訴之裁定", "核定訴訟標的價額之裁定", "命補正法定代理人之裁定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:35+00:00", "source_pdf_sha1": "391f7c61502f", "answer_pdf_sha1": "032ff59ad495", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "505", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00220', 'disabled-57f41407', 'disabled-57f41407-moex-113-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於原告就通常訴訟事件於第二審訴訟程序為訴之追加、變更，下列何者 須經被告同意，其追加、變更始為合法？', '["原告甲以乙為被告，主張乙所有之 B 屋無權占有甲所有之 A 地，依民 法第 767 條第 1 項規定，訴請乙拆除 B 屋，返還所占有之 A 地。嗣甲 發現B屋為乙、丙共有，乃追加丙為被告，請求乙、丙拆屋還地", "原告甲以乙為被告，主張其於某日遭乙毆打成傷，爰依侵權行為之規定， 訴請乙賠償新臺幣（下同）200 萬元。嗣甲發現丙於當日亦參與該毆打 行為，乃追加丙為被告，請求乙、丙連帶賠償200萬元", "原告甲以乙為被告，主張乙積欠其300萬元借款未還，爰依消費借貸之 法律關係，僅先就其中200萬元部分訴請乙返還。嗣甲於第二審程序主 張欲請求乙清償全部借款債務，乃改聲明請求乙給付300萬元", "原告甲以乙為被告，主張其向乙買受C地，已給付價金600萬元，爰依 買賣之法律關係，訴請乙移轉C地所有權。嗣甲發現乙於第一審訴訟程 序中，已將C地所有權移轉登記予丁，甲乃解除與乙之買賣契約，變更 聲明請求乙返還價金600萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:35+00:00", "source_pdf_sha1": "391f7c61502f", "answer_pdf_sha1": "032ff59ad495", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "505", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00221', 'disabled-57f41407', 'disabled-57f41407-moex-113-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於第三人撤銷訴訟之管轄法院，下列何者正確？', '["甲、乙就關於A屋買賣爭議事件，合意由B地（非甲、乙之住所地）之 地方法院管轄，經該法院判決確定後，丙欲提起第三人撤銷訴訟，不適 用「以原就被」原則，故不得向甲或乙之住所地之法院起訴", "對於審級不同之法院就同一事件所為之判決合併提起第三人撤銷訴訟 者，應向原第一審法院起訴，以保障當事人之審級利益", "僅對最高法院所為確定判決提起第三人撤銷訴訟者，應向最高法院起訴", "第三人撤銷訴訟之被告不抗辯法院無管轄權，而為本案之言詞辯論者， 該法院即為有管轄權之法院"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:35+00:00", "source_pdf_sha1": "391f7c61502f", "answer_pdf_sha1": "032ff59ad495", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "505", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00222', 'disabled-57f41407', 'disabled-57f41407-moex-113-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '下列何者為債務人對於已確定之支付命令之正確救濟方法？', '["提起再審", "提起確認債權不存在之訴，並聲請停止強制執行", "聲明異議", "提起撤銷支付命令之訴"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:35+00:00", "source_pdf_sha1": "391f7c61502f", "answer_pdf_sha1": "032ff59ad495", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "505", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00223', 'disabled-57f41407', 'disabled-57f41407-moex-113-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '債權人就金錢請求以外之請求，起訴前欲保全強制執行者，得以下列何種 程序為之？', '["聲請假扣押", "聲請假處分", "聲請發支付命令", "聲請假執行"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:35+00:00", "source_pdf_sha1": "391f7c61502f", "answer_pdf_sha1": "032ff59ad495", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "505", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00224', 'disabled-57f41407', 'disabled-57f41407-moex-113-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於除權判決，下列何者錯誤？', '["聲請除權判決，得於申報權利之公示催告期間已滿後3個月內聲請之", "法院就除權判決之聲請為裁判前，得依職權為必要之調查", "駁回除權判決之聲請，應以裁定為之", "對於除權判決，得上訴聲明不服"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:35+00:00", "source_pdf_sha1": "391f7c61502f", "answer_pdf_sha1": "032ff59ad495", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "505", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00225', 'disabled-57f41407', 'disabled-57f41407-moex-113-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '甲夫列乙妻為被告，起訴請求判決離婚，甲於判決確定前死亡。關於此離 婚訴訟，下列何者正確？', '["訴訟程序當然停止", "甲之繼承人得聲明承受訴訟", "訴訟當然終結", "若乙為甲之唯一繼承人，法院應以裁定駁回甲之訴 乙、刑事訴訟法部分"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:35+00:00", "source_pdf_sha1": "391f7c61502f", "answer_pdf_sha1": "032ff59ad495", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "505", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL)
